(1024, 31, 'Simulation: What happens if we apply this? div { box-sizing: border-box; width: 200px; padding: 20px; border: 5px solid; } d. Error', '', 'Final width = 200px', 'Final width = 250px', 'Final width = 230px', 'A', 'Beginner', 'Quiz question'),
(1025, 31, 'Which layout property allows elements to be placed side by side horizontally? d. inline', '', 'float', 'align', 'flex', 'A', 'Beginner', 'Quiz question'),
(1026, 31, 'Simulation: What happens with this CSS? img { float: right; } d. Image centers', '', 'Image sticks to the left side', 'Image moves to the right side', 'Image disappears', 'A', 'Beginner', 'Quiz question'),
(1027, 31, 'Which property is used to clear floated elements? d. reset', '', 'stop', 'break', 'clear', 'A', 'Beginner', 'Quiz question'),
(1028, 31, 'Simulation: What does this CSS do? div { display: inline-block; width: 150px; height: 100px; } d. Divs ignore width and height', '', 'Divs stack vertically', 'Divs act like inline text but keep box shape', 'Divs disappear', 'A', 'Beginner', 'Quiz question'),
(1029, 31, 'Which CSS property is used to control the spacing between elements in a flexbox or grid (modern)? d. margin-collapse', '', 'padding', 'gap', 'spacing', 'A', 'Beginner', 'Quiz question'),
(1030, 31, 'Simulation: What is the effect? div { display: flex; justify-content: space-between; } d. Items align vertically', '', 'Items stick together with no gap', 'Items spread out with space between them', 'Items all move to the left', 'A', 'Beginner', 'Quiz question'),
(1031, 31, 'Which of the following CSS properties is NOT part of the box model? d. font-size ✅ Answer: d. font-size', '', 'border', 'margin', 'padding', 'A', 'Beginner', 'Quiz question'),
(1032, 31, 'When two vertical margins meet, what happens in CSS? d. They cancel each other', '', 'They add together', 'They collapse to the larger margin', 'They collapse to the smaller margin', 'A', 'Intermediate', 'Quiz question'),
(1033, 31, 'Simulation: What will be the total width? div { width: 300px; padding: 20px; border: 10px solid black; margin: 15px; box-sizing: border-box; } d. 370px', '', '300px', '340px', '360px', 'A', 'Intermediate', 'Quiz question'),
(1034, 31, 'Which CSS property is used to control how an element is positioned relative to its normal position or container? d. z-index', '', 'float', 'position', 'align', 'A', 'Intermediate', 'Quiz question'),
(1035, 31, 'Simulation: What happens with this CSS? div { position: absolute; top: 50px; left: 100px; } d. Div becomes centered', '', 'Div stays in flow but shifted', 'Div is removed from normal flow and placed at (50px, 100px)', 'Div scrolls with content', 'A', 'Intermediate', 'Quiz question'),
(1036, 31, 'Which of the following layout models replaces float-based layouts in modern CSS? d. table', '', 'inline-block', 'grid', 'flexbox', 'A', 'Intermediate', 'Quiz question'),
(1037, 31, 'Simulation: What happens here? .container { display: flex; align-items: center; height: 200px; } d. Items align bottom', '', 'Items align horizontally center', 'Items align vertically center', 'Items align top', 'A', 'Intermediate', 'Quiz question'),
(1038, 31, 'Which CSS property sets the main axis direction in flexbox? d. justify-content', '', 'flex-flow', 'flex-direction', 'align-items', 'A', 'Intermediate', 'Quiz question'),
(1039, 31, 'Simulation: What does this CSS do? .container { display: flex; flex-direction: column; } d. Items disappear', '', 'Items placed in a row horizontally', 'Items stacked vertically', 'Items overlap each other', 'A', 'Intermediate', 'Quiz question'),
(1040, 31, 'In CSS Grid, which property defines the number of columns? d. columns', '', 'grid-template-columns', 'grid-template-rows', 'grid-columns', 'A', 'Intermediate', 'Quiz question');
REPLACE INTO `questions` (`id`, `topic_id`, `question_text`, `code_snippet`, `option_a`, `option_b`, `option_c`, `correct_option`, `class_level`, `question_type`) VALUES
(1041, 31, 'Simulation: What layout does this create? .container { display: grid; grid-template-columns: 100px 100px 100px; } d. A single 300px column', '', 'One row with 3 equal columns', 'Three rows stacked', 'Three columns of 100px each', 'A', 'Intermediate', 'Quiz question'),
(1042, 31, 'Which property allows a grid item to span multiple columns? d. span-column', '', 'grid-row', 'grid-area', 'grid-column', 'A', 'Intermediate', 'Quiz question'),
(1043, 31, 'Simulation: What happens with this CSS? .item { grid-column: 1 / 3; } d. No effect', '', 'Item occupies only the first column', 'Item spans across 2 columns', 'Item spans all 3 columns', 'A', 'Intermediate', 'Quiz question'),
(1044, 31, 'Which of the following helps prevent float elements from breaking layouts? d. z-index: 999;', '', 'clear: both;', 'position: fixed;', 'display: flex;', 'A', 'Intermediate', 'Quiz question'),
(1045, 31, 'Simulation: What happens? div { display: inline-block; width: 150px; margin: 10px; } d. Blocks ignore margin', '', 'Blocks stack vertically only', 'Blocks sit side by side if space allows', 'Blocks overlap each other', 'A', 'Intermediate', 'Quiz question'),
(1046, 31, 'Which of the following is TRUE about box-sizing: border-box;? d. It has no effect on layout', '', 'Padding and border are excluded from width/height', 'Padding and border are included inside width/height', 'Margins are included in total width', 'A', 'Intermediate', 'Quiz question'),
(1047, 34, 'Which method is commonly used to attach an event handler in JavaScript? d. onEvent()', '', 'getElement()', 'addEventListener()', 'setEvent()', 'A', 'Beginner', 'Quiz question'),
(1048, 34, 'Which of the following is an example of an inline event handler? d. onclick.alert(\'Hello!\')', '', '<button onclick=\"alert(\'Hello!\')\">Click Me</button>', 'button.addEventListener(\'click\', alert(\'Hello!\'))', '<button alert=\'Hello!\'>Click Me</button>', 'A', 'Beginner', 'Quiz question'),
(1049, 34, 'Simulation: What happens when this button is clicked? <button onclick=\"console.log(\'Clicked!\')\">Click Me</button> d. Button disappears', '', 'Nothing happens', 'Error in console', '“Clicked!” is printed in the console', 'A', 'Beginner', 'Quiz question'),
(1050, 34, 'Which event occurs when a user presses a key on the keyboard? d. keypressdown', '', 'onpress', 'onkeydown', 'onkeyupdown', 'A', 'Beginner', 'Quiz question'),
(1051, 34, 'Simulation: What does this code do? document.getElementById(\"btn\").addEventListener(\"click\", function() { alert(\"Hello World\"); }); d. Does nothing', '', 'Shows alert when page loads', 'Shows alert when the button is clicked', 'Shows alert when mouse moves', 'A', 'Beginner', 'Quiz question'),
(1052, 34, 'Which mouse event triggers when the user hovers over an element? d. onenter', '', 'onclick', 'onhover', 'onmouseover', 'A', 'Beginner', 'Quiz question'),
(1053, 34, 'Simulation: What happens? <input type=\"text\" onfocus=\"this.style.backgroundColor=\'yellow\'\"> d. The page reloads', '', 'The input text turns yellow when clicked/focused', 'The input text disappears', 'Nothing happens', 'A', 'Beginner', 'Quiz question'),
(1054, 34, 'What does the event.preventDefault() method do? d. Stops page loading', '', 'Stops JavaScript execution', 'Prevents the browser’s default action', 'Removes event handler', 'A', 'Beginner', 'Quiz question'),
(1055, 34, 'Simulation: What happens when the form is submitted? <form onsubmit=\"alert(\'Form submitted!\')\"> <button type=\"submit\">Submit</button> </form> d. The button disappears', '', 'Nothing happens', 'Page reloads silently', 'An alert box appears saying “Form submitted!”', 'A', 'Beginner', 'Quiz question'),
(1056, 34, 'Which property of the event object gives the element that triggered the event? d. event.id', '', 'event.value', 'event.target', 'event.object', 'A', 'Beginner', 'Quiz question'),
(1057, 34, 'Simulation: What happens? document.addEventListener(\"keydown\", function(e) { console.log(\"Key pressed: \" + e.key); }); d. Runs only once', '', 'Logs every key pressed in the console', 'Logs only Enter key', 'Throws error', 'A', 'Beginner', 'Quiz question'),
(1058, 34, 'Which event fires when the page has finished loading? d. onpage', '', 'onfinish', 'onready', 'onload', 'A', 'Beginner', 'Quiz question'),
(1059, 34, 'Simulation: What happens here? <img src=\"photo.jpg\" onerror=\"alert(\'Image not found!\')\"> d. Nothing', '', 'Alerts when image is found', 'Alerts when image fails to load', 'Alerts on page load', 'A', 'Beginner', 'Quiz question'),
(1060, 34, 'Which of the following attaches multiple event handlers to the same element? d. Only one is possible', '', 'Inline event', 'onclick = function(){}', 'addEventListener()', 'A', 'Beginner', 'Quiz question'),
(1061, 34, 'Simulation: What does this code do? let btn = document.getElementById(\"btn\"); btn.onclick = function() { alert(\"First Handler\"); }; btn.onclick = function() { alert(\"Second Handler\"); }; d. Throws error', '', 'Runs both alerts', 'Runs only “First Handler”', 'Runs only “Second Handler”', 'A', 'Beginner', 'Quiz question'),
(1062, 34, 'What is the default order of event propagation in JavaScript? d. No propagation', '', 'Capturing → Target → Bubbling', 'Bubbling → Target → Capturing', 'Target only', 'A', 'Intermediate', 'Quiz question'),
(1063, 34, 'Simulation: What is logged when the button is clicked? <div onclick=\"console.log(\'DIV clicked\')\"> <button onclick=\"console.log(\'BUTTON clicked\')\">Click Me</button> </div> d. Error', '', 'Only “DIV clicked”', 'Only “BUTTON clicked”', '“BUTTON clicked” then “DIV clicked”', 'A', 'Intermediate', 'Quiz question'),
(1064, 34, 'Which method stops further propagation of an event? d. event.halt()', '', 'event.preventDefault()', 'event.stopPropagation()', 'event.stopImmediatePropagation()', 'A', 'Intermediate', 'Quiz question'),
(1065, 34, 'Simulation: What happens here? document.getElementById(\"btn\").addEventListener(\"click\", function() { console.log(\"First handler\"); }); document.getElementById(\"btn\").addEventListener(\"click\", function() { console.log(\"Second handler\"); }); d. Error', '', 'Only first handler runs', 'Only second handler runs', 'Both handlers run', 'A', 'Intermediate', 'Quiz question'),
(1066, 34, 'Which property determines whether the event is in the capturing or bubbling phase? d. event.state', '', 'event.type', 'event.phase', 'event.eventPhase', 'A', 'Intermediate', 'Quiz question'),
(1067, 34, 'Simulation: What happens when you click the button? document.getElementById(\"btn\").addEventListener(\"click\", () => { console.log(this); }); d. Error', '', 'Logs the button element', 'Logs window', 'Logs null', 'A', 'Intermediate', 'Quiz question'),
(1068, 34, 'Which event listener option makes the event run during the capturing phase? d. onCapture: true', '', 'useCapture: true', 'capture: true', 'bubbling: false', 'A', 'Intermediate', 'Quiz question'),
(1069, 34, 'Simulation: What happens? document.getElementById(\"form\").addEventListener(\"submit\", function(e) { e.preventDefault(); console.log(\"Form submission stopped!\"); }); d. Error', '', 'Form submits normally', 'Form reloads page', 'Form does not submit, message logs', 'A', 'Intermediate', 'Quiz question'),
(1070, 34, 'Which method removes an event listener in JavaScript? d. stopEvent()', '', 'removeEvent()', 'detachEventListener()', 'removeEventListener()', 'A', 'Intermediate', 'Quiz question'),
(1071, 34, 'Simulation: What is logged when clicking the button? function handler1() { console.log(\"Handler 1\"); } function handler2() { console.log(\"Handler 2\"); } let btn = document.getElementById(\"btn\"); btn.addEventListener(\"click\", handler1); btn.addEventListener(\"click\", handler2); btn.removeEventListener(\"click\", handler1); btn.click(); d. No output', '', 'Both handlers run', 'Only “Handler 1”', 'Only “Handler 2”', 'A', 'Intermediate', 'Quiz question'),
(1072, 34, 'What is event delegation? d. Giving control of events to the browser', '', 'Assigning multiple events to one element', 'Using a parent element to handle events of its children', 'Passing events between JavaScript files', 'A', 'Intermediate', 'Quiz question'),
(1073, 34, 'Simulation: What happens when clicking <li>? document.getElementById(\"list\").addEventListener(\"click\", function(e) { if(e.target.tagName === \"LI\") { console.log(\"List item clicked:\", e.target.innerText); } }); d. Error', '', 'Nothing happens', 'Logs only when <ul> clicked', 'Logs which <li> was clicked', 'A', 'Intermediate', 'Quiz question'),
(1074, 34, 'Which property tells if event.preventDefault() was called? d. event.prevented', '', 'event.cancelled', 'event.isStopped', 'event.defaultPrevented', 'A', 'Intermediate', 'Quiz question'),
(1075, 34, 'Simulation: What happens here? document.getElementById(\"btn\").addEventListener(\"click\", function(e) { e.stopImmediatePropagation(); console.log(\"First\"); }); document.getElementById(\"btn\").addEventListener(\"click\", function() { console.log(\"Second\"); }); d. None run', '', 'Both run', 'Only “First” runs', 'Only “Second” runs', 'A', 'Intermediate', 'Quiz question'),
(1076, 34, 'Which event type is best to detect input changes as the user types? d. onkeyup', '', 'onchange', 'oninput', 'onkeydown', 'A', 'Intermediate', 'Quiz question'),
(1077, 28, 'What is the default order of event propagation in JavaScript? d. No propagation', '', 'Capturing → Target → Bubbling', 'Bubbling → Target → Capturing', 'Target only', 'A', 'Beginner', 'Quiz question'),
(1078, 28, 'Simulation: What is logged when the button is clicked? <div onclick=\"console.log(\'DIV clicked\')\"> <button onclick=\"console.log(\'BUTTON clicked\')\">Click Me</button> </div> d. Error', '', 'Only “DIV clicked”', 'Only “BUTTON clicked”', '“BUTTON clicked” then “DIV clicked”', 'A', 'Beginner', 'Quiz question'),
(1079, 28, 'Which method stops further propagation of an event? d. event.halt()', '', 'event.preventDefault()', 'event.stopPropagation()', 'event.stopImmediatePropagation()', 'A', 'Beginner', 'Quiz question'),
