(1088, 28, 'Simulation: What happens when clicking <li>? document.getElementById(\"list\").addEventListener(\"click\", function(e) { if(e.target.tagName === \"LI\") { console.log(\"List item clicked:\", e.target.innerText); } }); d. Error', '', 'Nothing happens', 'Logs only when <ul> clicked', 'Logs which <li> was clicked', 'A', 'Beginner', 'Quiz question'),
(1089, 28, 'Which property tells if event.preventDefault() was called? d. event.prevented', '', 'event.cancelled', 'event.isStopped', 'event.defaultPrevented', 'A', 'Beginner', 'Quiz question'),
