(1091, 28, 'Which event type is best to detect input changes as the user types? d. onkeyup', '', 'onchange', 'oninput', 'onkeydown', 'A', 'Beginner', 'Quiz question'),
(1092, 28, 'Which HTML5 tag is used to represent self-contained content like a blog post? d. <aside>', '', '<section>', '<article>', '<div>', 'A', 'Intermediate', 'Quiz question'),
(1093, 28, 'Simulation: What will be the output? <section> <h2>About Us</h2> <p>We are BSIT students.</p> </section> d. Throws an error', '', 'Creates a styled box', 'Groups “About Us” and paragraph together semantically', 'Hides content', 'A', 'Intermediate', 'Quiz question'),
(1094, 28, 'Which attribute is used to provide a unique identifier for an HTML element? d. key', '', 'class', 'id', 'name', 'A', 'Intermediate', 'Quiz question'),
(1095, 28, 'Simulation: What happens with this code? <input type=\"email\" required> d. No restriction', '', 'Accepts only text', 'Accepts only numbers', 'Requires a valid email format before submission', 'A', 'Intermediate', 'Quiz question'),
(1096, 28, 'Which HTML tag is used for the navigation links of a website? d. <aside>', '', '<menu>', '<nav>', '<header>', 'A', 'Intermediate', 'Quiz question'),
(1097, 28, 'Simulation: What happens here? <video controls> <source src=\"movie.mp4\" type=\"video/mp4\"> </video> d. Error', '', 'Displays video with play/pause controls', 'Shows only text “movie.mp4”', 'Doesn’t work without <embed>', 'A', 'Intermediate', 'Quiz question'),
(1098, 28, 'Which attribute is used in forms to send data to a server? d. both b and c ✅ Answer: d', '', 'src', 'action', 'method', 'A', 'Intermediate', 'Quiz question'),
(1099, 28, 'Simulation: What happens here? <form action=\"submit.php\" method=\"post\"> <input type=\"text\" name=\"username\"> <button type=\"submit\">Send</button> </form> d. Error', '', 'Nothing happens', 'Submits username to submit.php using POST method', 'Creates a local file', 'A', 'Intermediate', 'Quiz question'),
(1100, 28, 'Which HTML5 element is used for marking up content that is tangentially related to the main content? d. <main>', '', '<footer>', '<aside>', '<nav>', 'A', 'Intermediate', 'Quiz question'),
(1101, 28, 'Simulation: What does this code do? <audio controls> <source src=\"music.mp3\" type=\"audio/mpeg\"> </audio> d. Error', '', 'Plays audio with controls', 'Plays video instead', 'Shows text “music.mp3”', 'A', 'Intermediate', 'Quiz question'),
(1102, 28, 'Which element defines the main content of a webpage? d. <article>', '', '<main>', '<body>', '<section>', 'A', 'Intermediate', 'Quiz question'),
(1103, 28, 'Simulation: What happens with this code? <img src=\"student.jpg\" width=\"200\" height=\"100\"> d. Throws error', '', 'Displays image at original size', 'Resizes image to 200px wide and 100px tall', 'Stretches image to fit screen', 'A', 'Intermediate', 'Quiz question'),
(1104, 28, 'Which attribute provides alternative text for an image (for accessibility)? d. text', '', 'alt', 'src', 'title', 'A', 'Intermediate', 'Quiz question'),
(1105, 28, 'Simulation: What happens here? <input type=\"radio\" name=\"gender\" value=\"male\"> Male <input type=\"radio\" name=\"gender\" value=\"female\"> Female d. Error', '', 'Allows multiple selections', 'Allows only one option at a time', 'Shows checkboxes', 'A', 'Intermediate', 'Quiz question'),
(1106, 28, 'Which HTML element is used to group a set of form inputs with a label? d. <div> and <span>', '', '<fieldset> and <legend>', '<section> and <caption>', '<form> and <label>', 'A', 'Intermediate', 'Quiz question'),
(1107, 29, 'Which HTML tag is used to create a form? d. <label>', '', '<input>', '<form>', '<fieldset>', 'A', 'Beginner', 'Quiz question'),
(1108, 29, 'Which attribute of <form> specifies the script or file that will process the data? d. src', '', 'method', 'action', 'target', 'A', 'Beginner', 'Quiz question'),
(1109, 29, 'Simulation: What happens here? <form action=\"submit.php\" method=\"get\"> <input type=\"text\" name=\"username\"> <input type=\"submit\"> </form> d. Error', '', 'Nothing happens', 'Sends data as ?username=value in the URL', 'Submits data secretly', 'A', 'Beginner', 'Quiz question'),
(1110, 29, 'Which <input> type is used for entering passwords? d. type=\"hidden\"', '', 'type=\"text\"', 'type=\"password\"', 'type=\"secret\"', 'A', 'Beginner', 'Quiz question'),
(1111, 29, 'Simulation: What does this code do? <input type=\"radio\" name=\"gender\" value=\"male\"> Male <input type=\"radio\" name=\"gender\" value=\"female\"> Female d. Error', '', 'Allows selecting both Male and Female', 'Allows selecting only one option at a time', 'Creates checkboxes', 'A', 'Beginner', 'Quiz question'),
(1112, 29, 'Which input type is best for selecting multiple items from a list? d. submit', '', 'text', 'checkbox', 'radio', 'A', 'Beginner', 'Quiz question'),
(1113, 29, 'Simulation: What happens? <input type=\"checkbox\" name=\"skills\" value=\"HTML\"> HTML <input type=\"checkbox\" name=\"skills\" value=\"CSS\"> CSS d. Error', '', 'User can select only one option', 'User can select multiple options', 'Creates radio buttons', 'A', 'Beginner', 'Quiz question'),
(1114, 29, 'Which form element is used for a multi-line text input? d. <input type=\"longtext\">', '', '<input type=\"text\">', '<textarea>', '<textbox>', 'A', 'Beginner', 'Quiz question'),
(1115, 29, 'Simulation: What does this code do? <select name=\"year\"> <option value=\"1st\">1st Year</option> <option value=\"2nd\">2nd Year</option> <option value=\"3rd\">3rd Year</option> </select> d. Error', '', 'Creates a text field', 'Creates a drop-down menu with 3 options', 'Creates radio buttons', 'A', 'Beginner', 'Quiz question'),
(1116, 29, 'Which attribute makes a form field mandatory before submitting? d. disabled', '', 'required', 'checked', 'readonly', 'A', 'Beginner', 'Quiz question'),
(1117, 29, 'Simulation: What happens here? <input type=\"text\" name=\"student\" value=\"BSIT\" readonly> d. Error', '', 'Field is editable', 'Field is not editable but value is submitted', 'Field is not editable and not submitted', 'A', 'Beginner', 'Quiz question'),
(1118, 29, 'Which attribute disables an input field completely? d. hide', '', 'disabled', 'readonly', 'block', 'A', 'Beginner', 'Quiz question'),
(1119, 29, 'Simulation: What happens here? <input type=\"hidden\" name=\"token\" value=\"12345\"> d. Error', '', 'Field is visible and editable', 'Field is visible but disabled', 'Field is hidden but data is still submitted', 'A', 'Beginner', 'Quiz question'),
(1120, 29, 'Which input type is used for selecting a date? d. time', '', 'text', 'date', 'calendar', 'A', 'Beginner', 'Quiz question'),
(1121, 29, 'Simulation: What does this code do? <form> <input type=\"submit\" value=\"Send\"> <input type=\"reset\" value=\"Clear\"> </form> d. Error', '', 'Submit button sends form data, Reset button clears all fields', 'Both send the form', 'Both clear the form', 'A', 'Beginner', 'Quiz question'),
(1122, 29, 'Which <input> type allows a user to upload a file? d. type=\"document\"', '', 'type=\"text\"', 'type=\"file\"', 'type=\"upload\"', 'A', 'Intermediate', 'Quiz question'),
(1123, 29, 'Simulation: What does this code do? <input type=\"number\" min=\"1\" max=\"10\"> d. Accepts text and numbers', '', 'Accepts only whole numbers', 'Accepts numbers only between 1 and 10', 'Accepts all numbers', 'A', 'Intermediate', 'Quiz question'),
(1124, 29, 'Which input type creates a slider control? d. scale', '', 'range', 'slider', 'scroll', 'A', 'Intermediate', 'Quiz question'),
(1125, 29, 'Simulation: What is the output? <input type=\"color\" name=\"favColor\"> d. Error', '', 'A text box for color name', 'A drop-down for colors', 'A color picker tool', 'A', 'Intermediate', 'Quiz question'),
(1126, 29, 'Which input attribute is used to provide a hint inside the text box? d. alt', '', 'label', 'placeholder', 'title', 'A', 'Intermediate', 'Quiz question'),
(1127, 29, 'Simulation: What happens here? <input type=\"email\" required> d. Error', '', 'Accepts only text', 'Requires a valid email format before submission', 'Accepts numbers only', 'A', 'Intermediate', 'Quiz question'),
(1128, 29, 'Which input type is used to enter a website URL? d. type=\"href\"', '', 'type=\"web\"', 'type=\"link\"', 'type=\"url\"', 'A', 'Intermediate', 'Quiz question'),
(1129, 29, 'Simulation: What does this code do? <input type=\"tel\" pattern=\"[0-9]{10}\"> d. Error', '', 'Allows any text input', 'Accepts only numbers but no limit', 'Accepts exactly 10 digits', 'A', 'Intermediate', 'Quiz question'),
(1130, 29, 'Which form attribute is used to turn off browser autofill suggestions? d. disable', '', 'autocomplete=\"off\"', 'autofill=\"off\"', 'readonly', 'A', 'Intermediate', 'Quiz question'),
(1131, 29, 'Simulation: What happens here? <form action=\"submit.php\" method=\"post\" novalidate> <input type=\"email\" required> <input type=\"submit\"> </form> d. Prevents form submission', '', 'Validates email before submission', 'Submits form without validation', 'Shows error', 'A', 'Intermediate', 'Quiz question'),
(1132, 29, 'Which input type is best for choosing a time? d. type=\"clock\"', '', 'type=\"date\"', 'type=\"datetime-local\"', 'type=\"time\"', 'A', 'Intermediate', 'Quiz question'),
(1133, 29, 'Simulation: What happens here? <input type=\"password\" minlength=\"6\" maxlength=\"12\"> d. Error', '', 'Accepts any text', 'Accepts only passwords between 6–12 characters', 'Accepts only numbers', 'A', 'Intermediate', 'Quiz question'),
