(1512, 48, 'Which JDBC interface is used to execute parameterized queries? d. CallableStatement', '', 'PreparedStatement', 'Statement', 'ResultSet', 'A', 'Intermediate', 'Quiz question'),
(1513, 48, 'Simulation: What does this code do? PreparedStatement ps = con.prepareStatement(\"REPLACE INTO students(id, name) VALUES(?, ?)\"); ps.setInt(1, 1); ps.setString(2, \"BSIT\"); ps.executeUpdate(); d. Deletes a student record', '', 'Inserts a student record using parameters', 'Reads student data', 'Updates a student record', 'A', 'Intermediate', 'Quiz question'),
(1514, 48, 'Which method is used to execute multiple SQL statements as a batch? d. prepareBatch()', '', 'addBatch()', 'executeUpdate()', 'executeQuery()', 'A', 'Intermediate', 'Quiz question'),
(1515, 48, 'Simulation: What is the purpose of this code? ps.addBatch(\"REPLACE INTO students VALUES(2,\'IT\')\"); ps.addBatch(\"REPLACE INTO students VALUES(3,\'CS\')\"); ps.executeBatch(); d. Reads multiple records', '', 'Inserts multiple student records in one batch', 'Deletes multiple records', 'Updates multiple records', 'A', 'Intermediate', 'Quiz question'),
(1516, 48, 'Which JDBC feature allows rollback and commit? d. ResultSet', '', 'Transactions', 'Batch updates', 'PreparedStatement', 'A', 'Intermediate', 'Quiz question'),
(1517, 48, 'Simulation: What does this code do? con.setAutoCommit(false); try { stmt.executeUpdate(\"REPLACE INTO students VALUES(4,\'Math\')\"); stmt.executeUpdate(\"REPLACE INTO students VALUES(5,\'Science\')\"); con.commit(); } catch(SQLException e) { con.rollback(); } d. Only rolls back first insert', '', 'Executes both inserts as a transaction and rolls back on error', 'Executes inserts individually', 'Commits each statement automatically', 'A', 'Intermediate', 'Quiz question'),
(1518, 48, 'Which method prevents SQL injection in JDBC? d. Using DriverManager', '', 'Using PreparedStatement with parameters', 'Using Statement', 'Using ResultSet', 'A', 'Intermediate', 'Quiz question'),
(1519, 48, 'Simulation: What does this code do? PreparedStatement ps = con.prepareStatement(\"SELECT * FROM students WHERE name=?\"); ps.setString(1, \"BSIT\"); ResultSet rs = ps.executeQuery(); d. Deletes students', '', 'Selects students with name \"BSIT\" safely', 'Selects all students', 'Updates students', 'A', 'Intermediate', 'Quiz question'),
