(1592, 47, 'Simulation: What does this SQL statement do? REPLACE INTO students (id, name) VALUES (1, \'BSIT\'); d. Creates a table', '', 'Adds a new student record with id 1 and name BSIT', 'Deletes the student', 'Updates student name', 'A', 'Beginner', 'Quiz question'),
(1593, 47, 'Which SQL command is used to modify existing records? d. INSERT', '', 'UPDATE', 'SELECT', 'DELETE', 'A', 'Beginner', 'Quiz question'),
(1594, 47, 'Simulation: What does this SQL statement do? UPDATE students SET name=\'IT\' WHERE id=1; d. Selects a student', '', 'Changes the name of student with id 1 to IT', 'Deletes student', 'Adds a new student', 'A', 'Beginner', 'Quiz question'),
(1595, 47, 'Which SQL command is used to remove records from a table? d. SELECT', '', 'DELETE', 'INSERT', 'UPDATE', 'A', 'Beginner', 'Quiz question'),
(1596, 47, 'Simulation: What does this SQL statement do? DELETE FROM students WHERE id=1; d. Selects a student', '', 'Deletes the student record with id 1', 'Updates the student', 'Inserts a student', 'A', 'Beginner', 'Quiz question'),
(1597, 47, 'Which SQL command is used to create a new table? d. UPDATE', '', 'CREATE TABLE', 'REPLACE INTO', 'SELECT', 'A', 'Beginner', 'Quiz question'),
(1598, 47, 'Which of the following is a primary key? d. A column that can be empty', '', 'A column that uniquely identifies each record in a table', 'Any column', 'A column that stores text only', 'A', 'Beginner', 'Quiz question'),
(1599, 47, 'What is a foreign key? d. A key used to encrypt data', '', 'A column that refers to the primary key in another table', 'A unique identifier in the same table', 'A random column', 'A', 'Beginner', 'Quiz question'),
(1600, 47, 'Which type of database stores data in tables with rows and columns? d. Graph database', '', 'Relational database', 'NoSQL database', 'Key-value store', 'A', 'Beginner', 'Quiz question'),
(1601, 47, 'Why is database normalization important? d. To avoid using SQL', '', 'To reduce data redundancy and improve integrity', 'To make queries slower', 'To store data in files', 'A', 'Beginner', 'Quiz question'),
(1602, 47, 'Which SQL clause is used to combine rows from two or more tables based on a related column? d. ORDER BY', '', 'JOIN', 'WHERE', 'GROUP BY', 'A', 'Intermediate', 'Quiz question'),
(1603, 47, 'Simulation: What does this query do? SELECT students.name, courses.title FROM students JOIN courses ON students.course_id = courses.id; d. Creates a table', '', 'Displays student names with their course titles', 'Deletes students', 'Updates course titles', 'A', 'Intermediate', 'Quiz question'),
(1604, 47, 'Which SQL clause is used to filter records? d. ORDER BY', '', 'WHERE', 'HAVING', 'GROUP BY', 'A', 'Intermediate', 'Quiz question'),
(1605, 47, 'What is the purpose of a PRIMARY KEY constraint? d. Encrypts the data', '', 'Uniquely identifies each record in a table', 'Allows null values', 'Creates an index automatically', 'A', 'Intermediate', 'Quiz question'),
(1606, 47, 'What is a FOREIGN KEY constraint used for? d. Uniquely identifies records in the same table', '', 'Maintains referential integrity between tables', 'Encrypts data', 'Increases query speed', 'A', 'Intermediate', 'Quiz question'),
(1607, 47, 'Which SQL statement creates an index on a column? d. UPDATE', '', 'CREATE INDEX idx_name ON students(name);', 'CREATE TABLE', 'REPLACE INTO', 'A', 'Intermediate', 'Quiz question'),
(1608, 47, 'Simulation: What is the result of this query? SELECT course_id, COUNT(*) FROM students GROUP BY course_id; d. Updates course IDs', '', 'Counts the number of students in each course', 'Lists all students', 'Deletes grouped records', 'A', 'Intermediate', 'Quiz question'),
(1609, 47, 'Which SQL clause is used to filter groups after aggregation? d. GROUP BY', '', 'HAVING', 'WHERE', 'ORDER BY', 'A', 'Intermediate', 'Quiz question'),
(1610, 47, 'What is the difference between INNER JOIN and LEFT JOIN? d. INNER JOIN returns all rows', '', 'INNER JOIN returns only matching rows; LEFT JOIN returns all rows from the left table', 'LEFT JOIN returns only matching rows', 'No difference', 'A', 'Intermediate', 'Quiz question'),
(1611, 47, 'Simulation: What does this query return? SELECT * FROM students s LEFT JOIN courses c ON s.course_id = c.id; d. Nothing', '', 'All students, even if they have no matching course', 'Only students with courses', 'Only courses', 'A', 'Intermediate', 'Quiz question'),
(1612, 47, 'Which type of relationship is represented when one student can enroll in multiple courses? d. Self-Referencing', '', 'Many-to-Many', 'One-to-One', 'One-to-Many', 'A', 'Intermediate', 'Quiz question'),
(1613, 47, 'Which type of relationship is represented when one teacher teaches many students? d. Self-Referencing', '', 'One-to-Many', 'Many-to-Many', 'One-to-One', 'A', 'Intermediate', 'Quiz question'),
(1614, 47, 'What is the purpose of a UNIQUE constraint? d. Deletes duplicate records automatically', '', 'Ensures all values in a column are unique', 'Allows null values', 'Creates duplicate records', 'A', 'Intermediate', 'Quiz question'),
(1615, 47, 'Simulation: What happens if you try to insert a duplicate value into a column with a UNIQUE constraint? REPLACE INTO students(id, name) VALUES (1, \'BSIT\'); REPLACE INTO students(id, name) VALUES (1, \'IT\'); d. Ignored silently', '', 'SQL error occurs', 'Duplicate is inserted', 'First value is updated', 'A', 'Intermediate', 'Quiz question'),
(1616, 47, 'Which SQL clause is used to sort query results? d. HAVING', '', 'ORDER BY', 'GROUP BY', 'WHERE', 'A', 'Intermediate', 'Quiz question'),
(1617, 43, 'What is event-driven programming? d. A style that ignores user inputs', '', 'A programming paradigm where the flow of the program is determined by events such as user actions, sensor outputs, or messages from other programs', 'A sequential programming style', 'A programming style only for databases', 'A', 'Beginner', 'Quiz question'),
(1618, 43, 'Which of the following is an example of an event in programming? d. Importing a library', '', 'Clicking a button', 'Assigning a variable', 'Declaring a method', 'A', 'Beginner', 'Quiz question'),
(1619, 43, 'What is an event source? d. The output console', '', 'The object that generates an event, e.g., a button or text field', 'The method that handles the event', 'The listener interface', 'A', 'Beginner', 'Quiz question'),
(1620, 43, 'What is an event listener? d. A file containing code', '', 'An object that waits for and responds to events', 'A button on a GUI', 'A method to create events', 'A', 'Beginner', 'Quiz question'),
(1621, 43, 'Simulation: What happens here? JButton btn = new JButton(\"Click\"); btn.addActionListener(e -> System.out.println(\"Button clicked\")); d. Nothing', '', 'Prints \"Button clicked\" when the button is pressed', 'Prints immediately', 'Changes the button text', 'A', 'Beginner', 'Quiz question'),
(1622, 43, 'Which method is called when a button is clicked in Java Swing? d. windowClosing(WindowEvent e)', '', 'actionPerformed(ActionEvent e)', 'mouseClicked(MouseEvent e)', 'keyPressed(KeyEvent e)', 'A', 'Beginner', 'Quiz question'),
(1623, 43, 'Which programming languages commonly use event-driven programming? d. SQL only', '', 'Java, JavaScript, C#', 'C, C++ only', 'Assembly only', 'A', 'Beginner', 'Quiz question'),
(1624, 43, 'What is the main advantage of event-driven programming? d. Programs are shorter', '', 'Programs can respond immediately to user inputs', 'Programs run faster', 'Programs require no memory', 'A', 'Beginner', 'Quiz question'),
(1625, 43, 'What is an asynchronous event? d. A system error', '', 'An event that occurs independently of the main program flow', 'An event handled immediately before the next line', 'A sequential event', 'A', 'Beginner', 'Quiz question'),
(1626, 43, 'Which component can act as an event source in GUI programming? d. Class definition', '', 'Button, text field, window', 'Variable', 'Method', 'A', 'Beginner', 'Quiz question'),
(1627, 43, 'Which interface is commonly used to handle action events in Java? d. Cloneable', '', 'ActionListener', 'Runnable', 'Serializable', 'A', 'Beginner', 'Quiz question'),
(1628, 43, 'Simulation: What type of event is generated when a mouse is clicked? panel.addMouseListener(new MouseAdapter() { }); d. Window event', 'public void mouseClicked(MouseEvent e) { System.out.println(\"Clicked\"); }', 'Mouse event', 'Key event', 'Action event', 'A', 'Beginner', 'Quiz question'),
(1629, 43, 'Which of the following best describes event-driven architecture? d. A system that stores data', '', 'A system designed to detect events and respond to them', 'A system that runs only once', 'A system without user interaction', 'A', 'Beginner', 'Quiz question'),
(1630, 43, 'What is the relationship between event source and listener? d. The listener generates events', '', 'The listener listens to the source and responds when an event occurs', 'The source listens to the listener', 'They are unrelated', 'A', 'Beginner', 'Quiz question'),
(1631, 43, 'Why are adapter classes like MouseAdapter used in event-driven programming? d. To prevent exceptions', '', 'To allow overriding only the methods you need instead of all methods in a listener interface', 'To automatically generate events', 'To speed up the program', 'A', 'Beginner', 'Quiz question'),
(1632, 43, 'What is event delegation in event-driven programming? d. Propagating exceptions', '', 'Assigning a single handler to manage events for multiple components', 'Creating multiple handlers for each component', 'Ignoring events', 'A', 'Intermediate', 'Quiz question'),
(1633, 43, 'Simulation: What happens here? btn1.addActionListener(e -> System.out.println(\"Button 1 clicked\")); btn2.addActionListener(e -> System.out.println(\"Button 2 clicked\")); d. Nothing', '', 'Each button triggers its own listener when clicked', 'Only first button works', 'Both buttons trigger both listeners', 'A', 'Intermediate', 'Quiz question'),
(1634, 43, 'What is a custom event? d. A key press only', '', 'An event defined by the programmer to represent specific actions', 'Any system-generated event', 'A mouse click only', 'A', 'Intermediate', 'Quiz question'),
(1635, 43, 'Simulation: Which method is typically used to trigger a custom event? d. main()', '', 'fireEvent() or dispatchEvent()', 'addActionListener()', 'setVisible()', 'A', 'Intermediate', 'Quiz question'),
(1636, 43, 'Which listener interface is used to detect mouse motion events? d. ActionListener', '', 'MouseMotionListener', 'MouseListener', 'KeyListener', 'A', 'Intermediate', 'Quiz question'),
(1637, 43, 'Which listener interface detects focus changes in a component? d. KeyListener', '', 'FocusListener', 'ActionListener', 'MouseListener', 'A', 'Intermediate', 'Quiz question'),
(1638, 43, 'Simulation: What happens when a component gains focus? textField.addFocusListener(new FocusAdapter() { }); d. Throws error', 'public void focusGained(FocusEvent e) { System.out.println(\"Focus gained\"); }', 'Prints \"Focus gained\" when the component receives focus', 'Prints \"Focus lost\"', 'Prints nothing', 'A', 'Intermediate', 'Quiz question'),
(1639, 43, 'What is event propagation? d. Ignoring events', '', 'The process of sending events from the source component to interested listeners', 'Stopping all events', 'Repeating events multiple times', 'A', 'Intermediate', 'Quiz question'),
(1640, 43, 'Which listener is used for detecting component resizing or movement? d. MouseListener', '', 'ComponentListener', 'WindowListener', 'ActionListener', 'A', 'Intermediate', 'Quiz question'),
(1641, 43, 'Which listener detects window state changes like minimize or maximize? d. ActionListener', '', 'WindowStateListener', 'WindowListener', 'ComponentListener', 'A', 'Intermediate', 'Quiz question'),
(1642, 43, 'Simulation: What happens here? slider.addChangeListener(e -> System.out.println(slider.getValue())); d. Nothing', '', 'Prints slider value whenever adjusted', 'Prints initial value only', 'Prints maximum value only', 'A', 'Intermediate', 'Quiz question'),
(1643, 43, 'Why are adapter classes like MouseAdapter or FocusAdapter used? d. To prevent user input', '', 'To allow overriding only the methods needed instead of all methods in a listener interface', 'To automatically handle events', 'To speed up the program', 'A', 'Intermediate', 'Quiz question'),
(1644, 43, 'Simulation: What is the purpose of multiple listeners on a single component? btn.addActionListener(e -> System.out.println(\"Listener 1\")); btn.addActionListener(e -> System.out.println(\"Listener 2\")); d. Neither executes', '', 'Both listeners are executed when the event occurs', 'Only first listener executes', 'Only second listener executes', 'A', 'Intermediate', 'Quiz question'),
(1645, 43, 'What is the role of an event source in delegation? d. Creates multiple events automatically', '', 'Generates events and passes them to a single central handler', 'Handles events itself', 'Blocks other events', 'A', 'Intermediate', 'Quiz question'),
(1646, 43, 'Which of the following is a best practice in event-driven programming? d. Avoid using listeners', '', 'Keep event-handling methods short and delegate complex tasks', 'Put all code in event handler', 'Ignore exceptions in handlers', 'A', 'Intermediate', 'Quiz question'),
(1647, 46, 'What is the main purpose of layout management in Java GUI? d. To create events', '', 'To control the size and position of components within a container', 'To handle button clicks', 'To store data', 'A', 'Beginner', 'Quiz question'),
(1648, 46, 'Which layout manager arranges components in a single row or column? d. CardLayout', '', 'FlowLayout', 'GridLayout', 'BorderLayout', 'A', 'Beginner', 'Quiz question'),
(1649, 46, 'Simulation: What happens here? JPanel panel = new JPanel(); panel.setLayout(new FlowLayout()); panel.add(new JButton(\"OK\")); panel.add(new JButton(\"Cancel\")); d. Only one button shows', '', 'Buttons are arranged left to right in a row', 'Buttons overlap', 'Buttons are stacked vertically', 'A', 'Beginner', 'Quiz question'),
(1650, 46, 'Which layout manager divides the container into equal rows and columns? d. CardLayout', '', 'GridLayout', 'FlowLayout', 'BorderLayout', 'A', 'Beginner', 'Quiz question'),
(1651, 46, 'Simulation: What happens here? panel.setLayout(new GridLayout(2, 2)); panel.add(new JButton(\"A\")); panel.add(new JButton(\"B\")); panel.add(new JButton(\"C\")); panel.add(new JButton(\"D\")); d. Only two buttons appear', '', 'Buttons arranged in 2 rows and 2 columns', 'Buttons overlap', 'Buttons arranged in one row', 'A', 'Beginner', 'Quiz question'),
(1652, 46, 'Which layout manager divides the container into five regions: North, South, East, West, Center? d. BoxLayout', '', 'BorderLayout', 'FlowLayout', 'GridLayout', 'A', 'Beginner', 'Quiz question'),
(1653, 46, 'Simulation: What does this code do? frame.setLayout(new BorderLayout()); frame.add(new JButton(\"North\"), BorderLayout.NORTH); frame.add(new JButton(\"Center\"), BorderLayout.CENTER); d. Only one button appears', '', 'Places one button at top and one in the center', 'Overlaps buttons', 'Places buttons randomly', 'A', 'Beginner', 'Quiz question'),
(1654, 46, 'Which layout manager arranges components vertically or horizontally in a line? d. BorderLayout', '', 'BoxLayout', 'FlowLayout', 'GridLayout', 'A', 'Beginner', 'Quiz question'),
(1655, 46, 'Which layout manager allows switching between different components like cards? d. BorderLayout', '', 'CardLayout', 'FlowLayout', 'GridLayout', 'A', 'Beginner', 'Quiz question'),
(1656, 46, 'What is the default layout manager for a JPanel? d. BoxLayout', '', 'FlowLayout', 'BorderLayout', 'GridLayout', 'A', 'Beginner', 'Quiz question'),
(1657, 46, 'What is the default layout manager for a JFrame’s content pane? d. CardLayout', '', 'BorderLayout', 'FlowLayout', 'GridLayout', 'A', 'Beginner', 'Quiz question'),
(1658, 46, 'Simulation: What happens if you add multiple components to a BorderLayout.CENTER? d. Components disappear', '', 'Only the last added component is displayed', 'All components appear', 'Components are stacked', 'A', 'Beginner', 'Quiz question'),
(1659, 46, 'Which layout manager is best for aligning components without strict rows or columns? d. CardLayout', '', 'FlowLayout', 'GridLayout', 'BorderLayout', 'A', 'Beginner', 'Quiz question'),
(1660, 46, 'Why is using layout managers preferred over absolute positioning (setBounds)? d. Layout managers use less memory', '', 'Layout managers adjust components automatically when resizing', 'Absolute positioning is faster', 'Absolute positioning is easier', 'A', 'Beginner', 'Quiz question'),
(1661, 46, 'Which of the following is true about layout managers? d. They only work for AWT', '', 'They help create flexible and resizable GUI', 'They are not compatible with Swing', 'They always overlap components', 'A', 'Beginner', 'Quiz question'),
(1662, 46, 'What is a nested panel in GUI design? d. A panel used only in AWT', '', 'A panel added inside another panel to organize components', 'A panel placed outside the frame', 'A panel that cannot hold components', 'A', 'Intermediate', 'Quiz question'),
(1663, 46, 'Simulation: What layout combination is being used here? JPanel mainPanel = new JPanel(new BorderLayout()); JPanel topPanel = new JPanel(new FlowLayout()); mainPanel.add(topPanel, BorderLayout.NORTH); d. GridLayout for main panel', '', 'BorderLayout for main panel, FlowLayout for nested panel', 'FlowLayout for both panels', 'BorderLayout for both panels', 'A', 'Intermediate', 'Quiz question'),
(1664, 46, 'How do you set horizontal and vertical gaps between components in GridLayout? d. GridLayout.setGaps()', '', 'new GridLayout(rows, cols, hgap, vgap)', 'setGaps()', 'new GridLayout(hgap, vgap)', 'A', 'Intermediate', 'Quiz question'),
(1665, 46, 'Simulation: What happens here? GridLayout grid = new GridLayout(2, 3, 5, 10); panel.setLayout(grid); d. Throws error', '', 'Creates 2 rows, 3 columns with horizontal gap 5 and vertical gap 10', 'Creates overlapping components', 'Creates 3 rows, 2 columns', 'A', 'Intermediate', 'Quiz question'),
(1666, 46, 'Which layout manager allows aligning components along X or Y axis? d. BorderLayout', '', 'BoxLayout', 'FlowLayout', 'GridLayout', 'A', 'Intermediate', 'Quiz question'),
(1667, 46, 'Simulation: How to align a button to the right in a BoxLayout? button.setAlignmentX(Component.RIGHT_ALIGNMENT); d. Throws exception', '', 'Correct, aligns the button to the right', 'Incorrect, does nothing', 'Aligns to center', 'A', 'Intermediate', 'Quiz question'),
(1668, 46, 'What is the advantage of using nested panels with different layouts? d. Forces components to overlap', '', 'Allows flexible GUI arrangement and organization', 'Makes GUI slower', 'Prevents resizing', 'A', 'Intermediate', 'Quiz question'),
(1669, 46, 'Which layout manager is best for forms where labels and fields should align in a grid? d. CardLayout', '', 'GridBagLayout', 'FlowLayout', 'BorderLayout', 'A', 'Intermediate', 'Quiz question'),
(1670, 46, 'Simulation: Which code sets different column widths in GridBagLayout? GridBagConstraints gbc = new GridBagConstraints(); gbc.gridwidth = 2; d. Creates gap', '', 'Sets component to span 2 columns', 'Sets row height', 'Sets component alignment', 'A', 'Intermediate', 'Quiz question'),
(1671, 46, 'Which property is used to control spacing around a component in GridBagLayout? d. border', '', 'insets', 'gaps', 'padding', 'A', 'Intermediate', 'Quiz question'),
(1672, 46, 'What does weightx and weighty control in GridBagLayout? d. Component font size', '', 'How extra space is distributed among components', 'Component color', 'Component visibility', 'A', 'Intermediate', 'Quiz question'),
(1673, 46, 'Simulation: What happens here? panel.setLayout(new BoxLayout(panel, BoxLayout.Y_AXIS)); panel.add(button1); panel.add(button2); d. Only one button appears', '', 'Buttons are stacked vertically', 'Buttons arranged horizontally', 'Buttons overlap', 'A', 'Intermediate', 'Quiz question'),
(1674, 46, 'How do you combine FlowLayout and GridLayout effectively? d. Causes exceptions', '', 'Place a GridLayout panel inside a FlowLayout panel or vice versa', 'Use both on the same panel', 'Not possible', 'A', 'Intermediate', 'Quiz question'),
(1675, 46, 'Why is Box.createRigidArea() useful in layout management? d. Aligns components randomly', '', 'Adds fixed space between components', 'Deletes components', 'Resizes the frame automatically', 'A', 'Intermediate', 'Quiz question'),
(1676, 46, 'Which of the following is a best practice in layout management? d. Mix layouts randomly', '', 'Use nested panels with appropriate layouts for better organization', 'Avoid nested panels', 'Use absolute positioning for all components', 'A', 'Intermediate', 'Quiz question'),
